use std::collections::BinaryHeap;

fn solve(n: i64, edges: Vec<Vec<i64>>) -> i64 {
    let n = n as usize;
    let mut outgoing_edges = vec![vec![]; n];
    let mut incoming_edges = vec![vec![]; n];

    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let w = edge[2];
        outgoing_edges[u].push((v, w));
        incoming_edges[v].push((u, w));
    }

    let mut dist = vec![vec![i64::MAX; 2]; n];
    dist[0][0] = 0;

    let mut pq = BinaryHeap::new();
    pq.push((0, 0, 0));

    while let Some((cost, u, s)) = pq.pop() {
        if u == n - 1 {
            return cost;
        }
        if cost > dist[u][s] {
            continue;
        }

        // Process outgoing edges
        for (v, w) in &outgoing_edges[u] {
            let new_cost = cost + w;
            if new_cost < dist[*v][s] {
                dist[*v][s] = new_cost;
                pq.push((new_cost, *v, s));
            }
        }

        // Process incoming edges if switch not used
        if s == 0 {
            for (v, w) in &incoming_edges[u] {
                let new_cost = cost + 2 * w;
                if new_cost < dist[*v][1] {
                    dist[*v][1] = new_cost;
                    pq.push((new_cost, *v, 1));
                }
            }
        }
    }

    -1
}
